#!/usr/bin/env node
/**
 * Register Codex skills from the active Harnessy skills root.
 * Auto-generated by flow-install.
 */
import { GLOBAL_SKILLS_DIR, listActiveSkills, registerCodexSkills } from "./agents.mjs";

const run = async () => {
  const skills = await listActiveSkills(GLOBAL_SKILLS_DIR);
  const count = await registerCodexSkills(skills);
  console.log("Codex refreshed for " + count + " skill(s)");
};

run().catch((e) => {
  console.error("Codex registration failed:", e);
  process.exitCode = 1;
});
